def _resolve_font(root=None):
    try:
        import tkinter.font as tkfont
        fams = tkfont.families(root) if root else ()
        for f in ("Segoe UI", "Arial", "Helvetica"):
            if f in fams:
                return f
    except:
        pass
    return "Segoe UI"

UI_FONT = None

def _darken(hex_color):
    h = hex_color.lstrip("#")
    r, g, b = int(h[0:2],16), int(h[2:4],16), int(h[4:6],16)
    return f"#{max(0,r-30):02x}{max(0,g-30):02x}{max(0,b-30):02x}"

def styled_btn(parent, text, command=None, bg=None, fg=None, font=None, padx=14, pady=7, **kw):
    bg = bg or ACCENT
    fg = fg or (TEXT_ON_ACCENT if bg == ACCENT else TEXT)
    hover = _darken(bg)
    b = tk.Button(parent, text=text, command=command, bg=bg, fg=fg,
                  font=font or (UI_FONT, 10, "bold"),
                  activebackground=hover, activeforeground=fg,
                  relief="flat", bd=0, padx=padx, pady=pady,
                  cursor="hand2", highlightthickness=0, **kw)
    b.bind("<Enter>", lambda e: b.config(bg=hover))
    b.bind("<Leave>", lambda e: b.config(bg=bg))
    return b

def load_config():
    if os.path.exists(CONFIG_FILE):
        try:
            with open(CONFIG_FILE, "r", encoding="utf-8") as f:
                return json.load(f)
        except:
            pass
    return {"gemini_key": ""}

def save_config(cfg):
    try:
        with open(CONFIG_FILE, "w", encoding="utf-8") as f:
            json.dump(cfg, f, ensure_ascii=False, indent=2)
    except Exception as e:
        messagebox.showerror("Save Error", str(e))

def load_user_prompts():
    if os.path.exists(PROMPTS_FILE):
        try:
            with open(PROMPTS_FILE, "r", encoding="utf-8") as f:
                return json.load(f)
        except:
            pass
    return []

def save_user_prompts(prompts):
    try:
        with open(PROMPTS_FILE, "w", encoding="utf-8") as f:
            json.dump(prompts, f, ensure_ascii=False, indent=2)
    except Exception as e:
        messagebox.showerror("Save Error", str(e))

