def _vba_utilities(ignore_accents):
    if ignore_accents:
        norm = """
Function NormalizeForLCS(ByVal txt As String) As String
    NormalizeForLCS = LCase(StripPunct(RemoveAccents(txt)))
End Function

Function RemoveAccents(ByVal txt As String) As String
    Dim r As String: r = txt
    r = Replace(r, Chr(225),"a"): r = Replace(r, Chr(224),"a")
    r = Replace(r, Chr(226),"a"): r = Replace(r, Chr(228),"a")
    r = Replace(r, Chr(227),"a"): r = Replace(r, Chr(229),"a")
    r = Replace(r, Chr(233),"e"): r = Replace(r, Chr(232),"e")
    r = Replace(r, Chr(234),"e"): r = Replace(r, Chr(235),"e")
    r = Replace(r, Chr(237),"i"): r = Replace(r, Chr(236),"i")
    r = Replace(r, Chr(238),"i"): r = Replace(r, Chr(239),"i")
    r = Replace(r, Chr(243),"o"): r = Replace(r, Chr(242),"o")
    r = Replace(r, Chr(244),"o"): r = Replace(r, Chr(246),"o")
    r = Replace(r, Chr(245),"o"): r = Replace(r, Chr(248),"o")
    r = Replace(r, Chr(250),"u"): r = Replace(r, Chr(249),"u")
    r = Replace(r, Chr(251),"u"): r = Replace(r, Chr(252),"u")
    r = Replace(r, Chr(253),"y"): r = Replace(r, Chr(255),"y")
    r = Replace(r, Chr(241),"n"): r = Replace(r, Chr(231),"c")
    r = Replace(r, Chr(223),"ss")
    RemoveAccents = r
End Function"""
    else:
        norm = """
Function NormalizeForLCS(ByVal txt As String) As String
    NormalizeForLCS = LCase(StripPunct(txt))
End Function"""

    return norm + """

Function StripPunct(ByVal txt As String) As String
    Dim r As String: r = txt
    Do While Len(r) > 0
        Dim first As String: first = Left(r, 1)
        If first = "." Or first = "," Or first = "!" Or first = "?" Or first = ";" Then
            r = Mid(r, 2)
        Else
            Exit Do
        End If
    Loop
    Do While Len(r) > 0
        Dim last As String: last = Right(r, 1)
        If last = "." Or last = "," Or last = "!" Or last = "?" Or last = ";" Then
            r = Left(r, Len(r) - 1)
        Else
            Exit Do
        End If
    Loop
    StripPunct = r
End Function

Function SplitIntoWords(ByVal txt As String) As String()
    SplitIntoWords = Split(txt, " ")
End Function

Function CalculateLCS(orig() As String, modW() As String) As Long()
    Dim m As Long, n As Long, i As Long, j As Long
    m = UBound(orig) + 1: n = UBound(modW) + 1
    Dim mx() As Long: ReDim mx(0 To m, 0 To n)
    For i = 1 To m
        For j = 1 To n
            Dim on As String: on = NormalizeForLCS(orig(i-1))
            Dim mn As String: mn = NormalizeForLCS(modW(j-1))
            Dim bothEmpty As Boolean
            bothEmpty = (Len(on) = 0 And Len(mn) = 0)
            If (Not bothEmpty And on = mn) Or _
               (bothEmpty And LCase(orig(i-1)) = LCase(modW(j-1))) Then
                mx(i,j) = mx(i-1,j-1) + 1
            Else
                mx(i,j) = Application.WorksheetFunction.Max(mx(i-1,j), mx(i,j-1))
            End If
        Next j
    Next i
    CalculateLCS = mx
End Function

Function MarkChangedWords(mx() As Long, orig() As String, modW() As String) As Boolean()
    Dim m As Long, n As Long, i As Long, j As Long
    m = UBound(orig) + 1: n = UBound(modW) + 1
    Dim changed() As Boolean: ReDim changed(0 To n-1)
    For i = 0 To n-1: changed(i) = True: Next i
    i = m: j = n
    Do While i > 0 And j > 0
        Dim on2 As String: on2 = NormalizeForLCS(orig(i-1))
        Dim mn2 As String: mn2 = NormalizeForLCS(modW(j-1))
        Dim be2 As Boolean
        be2 = (Len(on2) = 0 And Len(mn2) = 0)
        If (Not be2 And on2 = mn2) Or _
           (be2 And LCase(orig(i-1)) = LCase(modW(j-1))) Then
            If LCase(orig(i-1)) = LCase(modW(j-1)) Then
                changed(j-1) = False
            End If
            i = i - 1: j = j - 1
        ElseIf mx(i-1,j) >= mx(i,j-1) Then
            i = i - 1
        Else
            j = j - 1
        End If
    Loop
    MarkChangedWords = changed
End Function

Sub ApplyHighlighting(cell As Range, words() As String, changed() As Boolean, _
                      ByVal hColor As Long, ByVal makeBold As Boolean, _
                      ByVal clearFirst As Boolean)
    Dim fullText As String: fullText = Join(words, " ")
    If Len(fullText) = 0 Then Exit Sub
    If clearFirst Then
        With cell.Characters(1, Len(fullText)).Font
            .Color = RGB(0,0,0): .Bold = False
        End With
    End If
    Dim pos As Long: pos = 1
    Dim w As Long
    For w = 0 To UBound(words)
        Dim wl As Long: wl = Len(words(w))
        If wl > 0 And changed(w) Then
            With cell.Characters(pos, wl).Font
                .Color = hColor
                If makeBold Then .Bold = True
            End With
        End If
        pos = pos + wl + 1
    Next w
End Sub"""

