def generate_bold_highlighter_vba(color_name):
    rgb = COLOR_MAP.get(color_name, "RGB(255,0,0)") or "RGB(255,0,0)"
    return f"""' ============================================================
' Popoko v{TOOL_VERSION} - Bold Text Highlighter
' ============================================================
Option Explicit

Sub HighlightBoldText()
    Dim ws As Worksheet: Set ws = ActiveSheet
    Dim targetCol As String
    Dim startRow As Long, endRow As Long
    Dim useSelection As Boolean: useSelection = False
    Dim sel As Range: Set sel = Selection

    If Not sel Is Nothing Then
        If sel.Columns.Count = 1 And sel.Rows.Count > 1 Then
            targetCol = Split(sel.Cells(1,1).Address(True,False),"$")(0)
            startRow = sel.Row
            endRow   = sel.Row + sel.Rows.Count - 1
            Dim warn As Integer
            warn = MsgBox("Process " & sel.Rows.Count & " rows in column " & targetCol & _
                          " (rows " & startRow & " to " & endRow & ")?" & vbNewLine & _
                          "Note: Row 1 may be a header.", vbQuestion + vbYesNo, "Popoko")
            If warn = vbNo Then Exit Sub
            useSelection = True
        ElseIf sel.Columns.Count > 1 Then
            Dim inp As String
            inp = InputBox("Multiple columns detected." & vbNewLine & _
                           "Enter the column letter with bold text to highlight:", _
                           "Popoko - Select Column")
            If inp = "" Then MsgBox "Cancelled.", vbInformation, "Popoko": Exit Sub
            targetCol = UCase(Trim(inp))
        Else
            Dim cinp As String
            cinp = InputBox("Enter the column letter to scan for bold text:", "Popoko - Select Column")
            If cinp = "" Then MsgBox "Cancelled.", vbInformation, "Popoko": Exit Sub
            targetCol = UCase(Trim(cinp))
        End If
    End If

    If Not useSelection Then
        Dim scanRow As Long, emptyCount As Long, lastData As Long
        scanRow = 1: emptyCount = 0: lastData = 1
        Do While emptyCount < 20
            If Trim(CStr(ws.Cells(scanRow, targetCol).Value)) = "" Then
                emptyCount = emptyCount + 1
            Else
                emptyCount = 0: lastData = scanRow
            End If
            scanRow = scanRow + 1
            If scanRow > ws.Rows.Count Then Exit Do
        Loop
        startRow = 1: endRow = lastData
    End If

    Dim r As Long, processed As Long: processed = 0
    For r = startRow To endRow
        Dim cell As Range: Set cell = ws.Cells(r, targetCol)
        Dim ct As String: ct = CStr(cell.Value)
        If Len(ct) > 0 Then
            Dim c As Long
            For c = 1 To Len(ct)
                If cell.Characters(c,1).Font.Bold = True Then
                    cell.Characters(c,1).Font.Color = {rgb}
                    processed = processed + 1
                End If
            Next c
        End If
    Next r
    MsgBox "Done! " & processed & " bold character(s) highlighted in column " & targetCol & ".", _
           vbInformation, "Popoko - Bold Highlighter"
End Sub
"""

LANG_NAMES = {
    "fr": "French", "es": "Spanish", "de": "German", "it": "Italian",
    "pt": "Portuguese", "nl": "Dutch", "pl": "Polish", "ru": "Russian",
    "ar": "Arabic", "zh": "Chinese", "ja": "Japanese", "ko": "Korean",
    "tr": "Turkish", "sv": "Swedish", "da": "Danish", "fi": "Finnish",
    "nb": "Norwegian", "cs": "Czech", "ro": "Romanian", "hu": "Hungarian",
    "el": "Greek", "he": "Hebrew", "th": "Thai", "vi": "Vietnamese",
    "id": "Indonesian", "ms": "Malay", "uk": "Ukrainian", "ca": "Catalan",
    "en": "English",
}

def _gtranslate(text, src="auto", tgt="en"):
    params = urllib.parse.urlencode({
        "client": "gtx", "sl": src, "tl": tgt, "dt": "t", "q": text
    })
    url = f"https://translate.googleapis.com/translate_a/single?{params}"
    req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
    for attempt in range(3):
        try:
            with urllib.request.urlopen(req, timeout=15) as r:
                data = json.loads(r.read())
            translated = "".join(p[0] for p in data[0] if p[0])
            detected = data[2] if len(data) > 2 else src
            return translated, detected
        except Exception:
            if attempt < 2:
                time.sleep(3)
    return text, src

def detect_and_translate(text, lang_code_hint=None):
    if lang_code_hint and lang_code_hint.lower() == "en":
        return text, "en", "English"
    translation, detected_code = _gtranslate(text, src=lang_code_hint or "auto", tgt="en")
    detected_code = str(detected_code).lower().split("-")[0]
    lang_name = LANG_NAMES.get(detected_code, detected_code.upper())
    return translation, detected_code, lang_name

def _fix_decimal_space(m):
    pre = re.sub(r"[, ]", "", m.group(1))
    post = m.group(2)
    pre = re.sub(r"(\d)(?=(\d{3})+$)", r"\1 ", pre)
    return f"{pre},{post}"

def _fix_decimal_dot(m):
    pre = re.sub(r"[, ]", "", m.group(1))
    post = m.group(2)
    pre = re.sub(r"(\d)(?=(\d{3})+$)", r"\1.", pre)
    return f"{pre},{post}"

def _fix_whole_space(text):
    def repl(m):
        n = m.group(0).replace(",", "").replace(".", "")
        return re.sub(r"(\d)(?=(\d{3})+$)", r"\1 ", n)
    return re.sub(r"\d{1,3}(?:,\d{3})+(?!\d)", repl, text)

def _fix_whole_dot(text):
    def repl(m):
        n = m.group(0).replace(",", "")
        return re.sub(r"(\d)(?=(\d{3})+$)", r"\1.", n)
    return re.sub(r"\d{1,3}(?:,\d{3})+(?!\d)", repl, text)

def correct_french(text):
    text = re.sub(r"(\d[\d,]*\s*)\.(\d+)", _fix_decimal_space, text)
    text = _fix_whole_space(text)
    text = re.sub(r"(?<!\w)\$\s*(\d)", r"\1 $", text)
    text = re.sub(r"(?<!\w)€\s*(\d)", r"\1 €", text)
    text = re.sub(r"(\d)%", r"\1 %", text)
    text = re.sub(r"\b(\d{1,2}):(\d{2})\b(?!:\d)", r"\1h\2", text)
    return text

def correct_spanish(text):
    text = re.sub(r"(\d[\d,]*\s*)\.(\d+)", _fix_decimal_dot, text)
    text = _fix_whole_dot(text)
    text = re.sub(r"(?<!\w)\$\s*(\d)", r"\1 $", text)
    text = re.sub(r"(\d)%", r"\1 %", text)
    return text

def correct_german(text):
    text = re.sub(r"(\d[\d,]*\s*)\.(\d+)", _fix_decimal_dot, text)
    text = _fix_whole_dot(text)
    text = re.sub(r"(\d)%", r"\1 %", text)
    return text

def correct_indonesian(text):
    def fix_decimal(m):
        pre = re.sub(r"[,. ]", "", m.group(1))
        post = m.group(2)
        pre = re.sub(r"(\d)(?=(\d{3})+$)", r"\1.", pre)
        return f"{pre},{post}"
    text = re.sub(r"(\d[\d,.]*)\.(\d+)", fix_decimal, text)
    def fix_whole(m):
        n = m.group(0).replace(",", "")
        return re.sub(r"(\d)(?=(\d{3})+$)", r"\1.", n)
    text = re.sub(r"\d{1,3}(?:,\d{3})+(?!\d)", fix_whole, text)
    text = re.sub(r"\b(\d{1,2}):(\d{2})\b(?!:\d)", r"\1.\2", text)
    return text

CORRECTORS = {
    "fr": correct_french,
    "es": correct_spanish,
    "de": correct_german,
    "it": correct_spanish,
    "pt": correct_spanish,
    "id": correct_indonesian,
    "ms": correct_indonesian,
}

def apply_locale_corrections(text, lang_code):
    corrector = CORRECTORS.get(str(lang_code).lower())
    return corrector(text) if corrector else text

def compute_corrections(original, corrected):
    orig_tokens = re.findall(r"\S+|\s+", original)
    corr_tokens = re.findall(r"\S+|\s+", corrected)
    sm = difflib.SequenceMatcher(None, orig_tokens, corr_tokens, autojunk=False)
    corrections = []
    for op, i1, i2, j1, j2 in sm.get_opcodes():
        if op in ("replace", "insert"):
            orig_phrase = "".join(orig_tokens[i1:i2]).strip()
            corr_phrase = "".join(corr_tokens[j1:j2]).strip()
            if corr_phrase and corr_phrase in corrected:
                corrections.append({"original": orig_phrase, "corrected": corr_phrase})
    return corrections

def build_remarks(corrections, lang_name):
    if not corrections:
        return "No changes required."
    parts = []
    for c in corrections:
        if c["original"]:
            parts.append(f'"{c["original"]}" -> "{c["corrected"]}"')
        else:
            parts.append(f'Added "{c["corrected"]}"'  )
    summary = "; ".join(parts[:4])
    if len(corrections) > 4:
        summary += f" (+{len(corrections)-4} more)"
    return f"Locale corrections applied for {lang_name}: {summary}."

def _build_correction_intervals(corrected_text, corrections):
    intervals = []
    for c in corrections:
        phrase = c.get("corrected", "").strip()
        if not phrase:
            continue
        start = 0
        while True:
            idx = corrected_text.find(phrase, start)
            if idx == -1:
                break
            end = idx + len(phrase)
            after = corrected_text[end] if end < len(corrected_text) else ""
            if after and (after.isalpha() or after.isdigit()):
                start = idx + 1
                continue
            intervals.append((idx, end))
            start = end
    intervals.sort()
    merged = []
    for s, e in intervals:
        if merged and s <= merged[-1][1]:
            merged[-1] = (merged[-1][0], max(merged[-1][1], e))
        else:
            merged.append([s, e])
    return merged

def apply_red_corrections(ws_cell_ref, corrected_text, corrections):
    from openpyxl.cell.rich_text import CellRichText, TextBlock
    from openpyxl.cell.text import InlineFont
    if not corrections or not corrected_text:
        ws_cell_ref.value = corrected_text
        return
    red_font    = InlineFont(color="FFFF0000")
    normal_font = InlineFont()
    merged = _build_correction_intervals(corrected_text, corrections)
    if not merged:
        ws_cell_ref.value = corrected_text
        return
    blocks = []
    pos = 0
    for s, e in merged:
        if s > pos:
            blocks.append(TextBlock(normal_font, corrected_text[pos:s]))
        blocks.append(TextBlock(red_font, corrected_text[s:e]))
        pos = e
    if pos < len(corrected_text):
        blocks.append(TextBlock(normal_font, corrected_text[pos:]))
    ws_cell_ref.value = CellRichText(*blocks)

def _find_header_and_data_row(ws):
    for r in range(1, min(10, ws.max_row + 1)):
        for c in range(1, 6):
            val = str(ws.cell(row=r, column=c).value or "").strip().lower()
            if val in ("id", "sender", "message", "platform", "language"):
                return r, r + 1
    return 1, 2

def process_excel_file(filepath, progress_cb, stop_event):
    import openpyxl
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side

    wb = openpyxl.load_workbook(filepath)
    ws = wb.active

    header_row, data_start = _find_header_and_data_row(ws)
    last_row = ws.max_row
    if last_row < data_start:
        return None, "No data rows found."

    J_COL = 10
    K_COL = 11
    L_COL = 12
    T_COL = 20
    NEW_COLS = list(range(J_COL, T_COL + 1))

    thin = Side(border_style="thin", color="000000")
    full_border = Border(left=thin, right=thin, top=thin, bottom=thin)
    header_font = Font(bold=True, color="111111")
    header_fill = PatternFill(start_color="F5E642", end_color="F5E642", fill_type="solid")

    headers = {
        J_COL: "Translation",  K_COL: "Reviewed Sample",
        L_COL: "L1 Reviewed",  13: "L2 Reviewed",
        14: "L3 Reviewed",     15: "L4 Reviewed",
        16: "L1 Reviewed",     17: "L2 Reviewed",
        18: "L3 Reviewed",     19: "L4 Reviewed",
        T_COL: "Remarks",
    }
    for col, hdr in headers.items():
        cell = ws.cell(row=header_row, column=col)
        cell.value = hdr
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center")
        cell.border = full_border

    detected_lang_name = None

    for row in range(data_start, last_row + 1):
        if stop_event.is_set():
            return None, "Stopped by user."

        message_text = str(ws.cell(row=row, column=3).value or "").strip()
        lang_hint    = str(ws.cell(row=row, column=5).value or "").strip()

        if not message_text:
            for col in NEW_COLS:
                ws.cell(row=row, column=col).border = full_border
            progress_cb(row, "Skipped", "Empty cell")
            continue

        progress_cb(row, "Processing", "")

        try:
            translation, detected_code, lang_name = detect_and_translate(
                message_text, lang_hint or None)
        except Exception as e:
            translation, detected_code, lang_name = "", lang_hint or "unknown", lang_hint or "Unknown"

        corrected   = apply_locale_corrections(message_text, detected_code)
        corrections = compute_corrections(message_text, corrected)
        remarks     = build_remarks(corrections, lang_name)

        if detected_lang_name is None:
            detected_lang_name = lang_name
            lang_cell = ws.cell(row=data_start, column=J_COL)
            if not lang_cell.value:
                lang_cell.value = lang_name

        j_cell = ws.cell(row=row, column=J_COL)
        j_cell.value = translation
        j_cell.border = full_border
        j_cell.alignment = Alignment(wrap_text=True)

        k_cell = ws.cell(row=row, column=K_COL)
        apply_red_corrections(k_cell, corrected, corrections)
        k_cell.border = full_border
        k_cell.alignment = Alignment(wrap_text=True)

        for src_col, dst_col in [(6, L_COL), (7, 13), (8, 14), (9, 15)]:
            src_val = ws.cell(row=row, column=src_col).value
            c = ws.cell(row=row, column=dst_col)
            c.value = src_val
            c.border = full_border

        for col in range(16, 20):
            ws.cell(row=row, column=col).border = full_border

        t_cell = ws.cell(row=row, column=T_COL)
        t_cell.value = remarks
        t_cell.alignment = Alignment(wrap_text=True)
        t_cell.border = full_border

        progress_cb(row, "Done", lang_name)

    base, ext = os.path.splitext(filepath)
    out_path = base + "_processed" + ext
    wb.save(out_path)
    return out_path, None

class SidebarBtn(tk.Frame):
    def __init__(self, parent, icon, label, command, **kw):
        super().__init__(parent, bg=SIDEBAR_BG, cursor="hand2")
        self._active = False
        self._cmd = command
        self._icon_lbl = tk.Label(self, text=icon, bg=SIDEBAR_BG, fg=TEXT_DIM,
                                  font=(UI_FONT, 14))
        self._icon_lbl.pack(pady=(14, 0))
        self._text_lbl = tk.Label(self, text=label, bg=SIDEBAR_BG, fg=TEXT_DIM,
                                  font=(UI_FONT, 8))
        self._text_lbl.pack(pady=(2, 14))
        for w in (self, self._icon_lbl, self._text_lbl):
            w.bind("<Button-1>", self._click)
            w.bind("<Enter>", self._hover_on)
            w.bind("<Leave>", self._hover_off)

    def _click(self, e=None):
        self._cmd()

    def _hover_on(self, e=None):
        if not self._active:
            for w in (self, self._icon_lbl, self._text_lbl):
                w.config(bg="#222222")

    def _hover_off(self, e=None):
        if not self._active:
            for w in (self, self._icon_lbl, self._text_lbl):
                w.config(bg=SIDEBAR_BG)

    def set_active(self, active):
        self._active = active
        bg = BG if active else SIDEBAR_BG
        fg_icon = ACCENT if active else TEXT_DIM
        fg_text = ACCENT if active else TEXT_DIM
        self.config(bg=bg)
        self._icon_lbl.config(bg=bg, fg=fg_icon)
        self._text_lbl.config(bg=bg, fg=fg_text)


