    def _build_comparison_ui(self, parent):
        tk.Label(parent, text="COLUMN COMPARISON", bg=CARD_BG, fg=ACCENT,
                 font=(UI_FONT, 9, "bold")).pack(anchor="w", pady=(0, 8))
        mode_frame = tk.Frame(parent, bg=CARD_BG)
        mode_frame.pack(anchor="w", pady=(0, 8))
