    def _color_swatch(self, parent, name, group):
        wrap = tk.Frame(parent, bg=CARD_BG)
        wrap.pack(side="left", padx=5, pady=3)
        btn = tk.Label(wrap, width=3, height=1, bg=COLOR_HEX[name],
                       cursor="hand2", relief="solid", bd=2)
        btn.pack()
        btn.bind("<Button-1>", lambda e, n=name, g=group: self._select_color(n, g))
        lbl = tk.Label(wrap, text=name, bg=CARD_BG, fg=TEXT_DIM, font=(UI_FONT, 8))
        lbl.pack()
        btn._name = name
        btn._lbl = lbl
        self._swatches[group].append(btn)
        if name == "Red":
            btn.config(bd=3)
            lbl.config(fg=ACCENT)

    def _select_color(self, name, group):
        if group == "main":
            self.selected_color = name
        else:
            self.bold_color = name
        for s in self._swatches[group]:
            s.config(bd=2)
            s._lbl.config(fg=TEXT_DIM)
        for s in self._swatches[group]:
            if s._name == name:
                s.config(bd=3)
                s._lbl.config(fg=ACCENT)

