        inner_fc2 = tk.Frame(files_card, bg=CARD_BG)
        inner_fc2.pack(fill="x", padx=16, pady=14)
        tk.Label(inner_fc2, text="FILES FOUND", bg=CARD_BG, fg=ACCENT,
                 font=(UI_FONT, 9, "bold")).pack(anchor="w", pady=(0, 6))
        self._files_frame = tk.Frame(inner_fc2, bg=CARD_BG)
