    def _browse_folder(self):
        path = filedialog.askdirectory()
        if path:
            self._folder_var.set(path)
            self._scan_folder()

    def _scan_folder(self):
        folder = self._folder_var.get().strip()
        if not folder or not os.path.isdir(folder):
            messagebox.showwarning("Invalid Folder", "Please select a valid folder first.")
            return
        files = [f for f in os.listdir(folder)
                 if f.endswith(".xlsx") and not f.startswith("~")]
        for w in self._files_frame.winfo_children():
            w.destroy()
        self._file_vars = {}
        if not files:
            tk.Label(self._files_frame, text="No .xlsx files found.",
                     bg=CARD_BG, fg=TEXT_DIM, font=(UI_FONT, 9)).pack(anchor="w")
            return
        for fname in sorted(files):
            var = tk.BooleanVar(value=True)
            self._file_vars[fname] = var
            cb = tk.Checkbutton(self._files_frame, text=fname, variable=var,
                                bg=CARD_BG, fg=TEXT, selectcolor=SURFACE2,
                                activebackground=CARD_BG, activeforeground=TEXT,
                                font=(UI_FONT, 9))
            cb.pack(anchor="w", pady=1)

    def _start_batch(self):
        folder = self._folder_var.get().strip()
        if not folder:
            messagebox.showwarning("No Folder", "Please select and scan a folder first.")
            return
        selected = [f for f, var in self._file_vars.items() if var.get()]
        if not selected:
            messagebox.showwarning("No Files", "Please select at least one file to process.")
            return

        for item in self._proc_tree.get_children():
            self._proc_tree.delete(item)
        self._proc_rows = {}

        self._stop_event.clear()
        self._run_btn.config(state="disabled")
        self._stop_btn.config(state="normal")
        self._status_lbl.config(text="Running...")

        t = threading.Thread(target=self._run_batch,
                             args=(folder, selected), daemon=True)
        t.start()

    def _run_batch(self, folder, files):
        for fname in files:
            if self._stop_event.is_set():
                break
            filepath = os.path.join(folder, fname)

            self.after(0, self._add_file_row, fname)

            def make_cb(fn):
                def cb(row, status, detail):
                    self.after(0, self._update_progress, fn, row, status, detail)
                return cb

            out_path, err = process_excel_file(
                filepath, make_cb(fname), self._stop_event)

            if err:
                self.after(0, self._update_progress, fname, "—", "Error", err)
                self.after(0, self._batch_error, fname, err)
                return

            self.after(0, self._update_progress, fname, "—", "Saved", f"→ {os.path.basename(out_path)}")

        self.after(0, self._batch_done)

    def _add_file_row(self, fname):
        iid = self._proc_tree.insert("", "end",
                                      values=(fname, "—", "Queued", ""))
        self._proc_rows[fname] = {"file_iid": iid, "row_iids": {}}

    def _update_progress(self, fname, row, status, detail):
        if fname not in self._proc_rows:
            return
        state = self._proc_rows[fname]
        row_key = str(row)

        if row_key not in state["row_iids"] and row != "—":
            iid = self._proc_tree.insert("", "end",
                                          values=("", str(row), status, detail))
            state["row_iids"][row_key] = iid
        elif row_key in state["row_iids"]:
            iid = state["row_iids"][row_key]
            self._proc_tree.item(iid, values=("", str(row), status, detail))
        else:
            iid = state["file_iid"]
            self._proc_tree.item(iid, values=(fname, str(row), status, detail))

        self._proc_tree.see(list(state["row_iids"].values())[-1]
                            if state["row_iids"] else state["file_iid"])

    def _batch_error(self, fname, err):
        self._run_btn.config(state="normal")
        self._stop_btn.config(state="disabled")
        self._status_lbl.config(text=f"Stopped: error in {fname}")
        messagebox.showerror("Batch Error",
            f"Processing stopped.\n\nFile: {fname}\nError: {err}\n\nFix the issue and retry.")

    def _batch_done(self):
        self._run_btn.config(state="normal")
        self._stop_btn.config(state="disabled")
        self._status_lbl.config(text="Batch complete.")
        messagebox.showinfo("Done", "Batch processing complete.")

    def _stop_batch(self):
        self._stop_event.set()
        self._status_lbl.config(text="Stopping...")

    def _build_prompts_section(self):
        sec = self._make_section("prompts")
        self._section_title(sec, "Prompts Library")

        paned = tk.PanedWindow(sec, orient="horizontal", bg=BORDER,
                               sashwidth=4, sashrelief="flat")
