class AddPromptWindow(tk.Toplevel):
    def __init__(self, parent, on_save):
        super().__init__(parent)
        self.title("Add New Prompt")
        self.configure(bg=BG)
        self.geometry("560x440")
        self.resizable(False, False)
        self.on_save = on_save
        self.update_idletasks()
        self.geometry(f"+{self.winfo_screenwidth()//2-280}+{self.winfo_screenheight()//2-220}")
        self._build()

    def _build(self):
        hdr = tk.Frame(self, bg=ACCENT, height=42)
        hdr.pack(fill="x")
        hdr.pack_propagate(False)
        tk.Label(hdr, text="Add New Prompt", bg=ACCENT, fg=TEXT_ON_ACCENT,
                 font=(UI_FONT, 12, "bold")).pack(side="left", padx=14, pady=10)

        body = tk.Frame(self, bg=BG)
        body.pack(fill="both", expand=True, padx=16, pady=14)

        tk.Label(body, text="Title:", bg=BG, fg=TEXT,
                 font=(UI_FONT, 10, "bold")).pack(anchor="w")
        self.title_entry = tk.Entry(body, bg=SURFACE2, fg=TEXT,
                                     insertbackground=TEXT, relief="flat",
                                     font=(UI_FONT, 10))
        self.title_entry.pack(fill="x", pady=(3, 10))

        tk.Label(body, text="Prompt Content:", bg=BG, fg=TEXT,
                 font=(UI_FONT, 10, "bold")).pack(anchor="w")
        self.content_box = scrolledtext.ScrolledText(
            body, height=12, font=(UI_FONT, 9),
            bg=SURFACE2, fg=TEXT, relief="flat", bd=0, wrap="word")
        self.content_box.pack(fill="both", expand=True, pady=(3, 12))

        bf = tk.Frame(body, bg=BG)
        bf.pack(fill="x")
        styled_btn(bf, "Save", self._save,
                   font=(UI_FONT, 10, "bold"), pady=7).pack(side="left", padx=(0, 8))
        styled_btn(bf, "Cancel", self.destroy,
                   bg=SURFACE2, fg=TEXT, font=(UI_FONT, 10), pady=7).pack(side="left")

    def _save(self):
        title   = self.title_entry.get().strip()
        content = self.content_box.get("1.0", "end").strip()
        if not title:
            messagebox.showwarning("Missing Title", "Please enter a title.", parent=self)
            return
        if not content:
            messagebox.showwarning("Missing Content", "Please enter the prompt content.", parent=self)
            return
        self.on_save({"title": title, "content": content, "hardcoded": False})
        self.destroy()


